BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?prop (COUNT(*) as ?count) WHERE {
  VALUES ?elem {
    <http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::01%2520Components::Operational::APS::Black%2520Box%2520Specification::Structure::APS%2520Operational%2520Blackbox%2520Specification%2520JPL>
    <http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Project%2520Systems%2520Engineering::01%2520Components::Operational::TMT%2520Observatory%2520System::Black%2520Box%2520Specifications%2520for%2520Suppliers::APS%2520Black%2520Box%2520Specification%2520TMT>
  }
  ?elem ?prop ?value .
}
GROUP BY ?prop
ORDER BY DESC(?count)
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?diag ?name ?context WHERE {
  VALUES ?bb {
    <http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Project%2520Systems%2520Engineering::01%2520Components::Operational::TMT%2520Observatory%2520System::Black%2520Box%2520Specifications%2520for%2520Suppliers::APS%2520Black%20Box%20Specification%20TMT>
  }

  ?bb (vocab:Element_ownedElement|vocab:Element_ownedElement+|^vocab:Element_owner)* ?ownerOrChild .
  ?diag rdf:type vocab:Diagram .
  ?diag vocab:NamedElement_name ?name .
  OPTIONAL { ?diag vocab:context ?context }

  FILTER EXISTS {
    ?ownerOrChild vocab:Element_owner ?diag .
  }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?req ?reqName ?flowDef ?flowName WHERE {
  VALUES ?bb {
    <http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Project%2520Systems%2520Engineering::01%2520Components::Operational::TMT%2520Observatory%2520System::Black%2520Box%2520Specifications%2520for%2520Suppliers::APS%2520Black%2520Box%2520Specification%2520TMT>
  }

  ?flowDef vocab:NamedElement_name ?flowName .

  ?req rdf:type vocab:tmt%20requirement .
  ?req vocab:NamedElement_name ?reqName .

  # Try common downstream mapping patterns: satisfy/verify or allocation chains
  {
    ?bb (vocab:Element_ownedElement+|vocab:Namespace_member+|vocab:Package_packagedElement+)* ?req .
  } UNION {
    ?bb (vocab:Dependency_supplier+|^vocab:Dependency_supplier+|vocab:satisfy|vocab:verify)* ?req .
  } UNION {
    ?flowDef (vocab:Element_ownedElement+|vocab:Namespace_member+|vocab:Package_packagedElement+)* ?req .
    FILTER(CONTAINS(LCASE(STR(?flowName)), LCASE("flow")))
  }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?req ?reqName ?container ?containerName WHERE {
  VALUES ?bb {
    <http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Project%2520Systems%2520Engineering::01%2520Components::Operational::TMT%2520Observatory%2520System::Black%2520Box%2520Specifications%2520for%2520Suppliers::APS%2520Black%20Box%20Specification%20TMT>
  }

  # Require tmt_requirement directly contained (or 1-step member) under the APS black box block
  {
    ?bb vocab:Element_ownedElement ?req .
  } UNION {
    ?bb vocab:Element_ownedElement+ ?req .
    FILTER EXISTS { ?req vocab:NamedElement_name ?_n }
  } UNION {
    ?bb vocab:Namespace_member ?req .
  }

  ?req rdf:type vocab:tmt%20requirement .
  ?req vocab:NamedElement_name ?reqName .

  # find an enclosing container/view-definition that owns the requirement
  OPTIONAL {
    ?container (vocab:Element_ownedElement|vocab:Namespace_member|vocab:Package_packagedElement)+ ?req .
    ?container vocab:NamedElement_name ?containerName .
  }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?req ?reqName ?view ?viewName WHERE {
  VALUES ?bb {
    <http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Project%2520Systems%2520Engineering::01%2520Components::Operational::TMT%2520Observatory%2520System::Black%2520Box%2520Specifications%2520for%2520Suppliers::APS%2520Black%20Box%20Specification%20TMT>
  }

  # Start set: immediate contained elements of the APS block
  ?bb (vocab:Element_ownedElement|vocab:Namespace_member)+ ?child .
  FILTER(?child != ?bb)

  # Reach requirements via common downstream relation kinds (bounded 3 hops)
  ?req rdf:type vocab:tmt%20requirement .
  ?req vocab:NamedElement_name ?reqName .

  {
    ?child (vocab:Dependency_supplier|^vocab:Dependency_supplier|vocab:Dependency_client|^vocab:Dependency_client)+ ?req .
  }
  UNION
  {
    ?child (vocab:satisfy|vocab:verify|vocab:allocate)+ ?req .
  }

  # View/container that owns the requirement
  OPTIONAL {
    ?view (vocab:Element_ownedElement|vocab:Namespace_member|vocab:Package_packagedElement)+ ?req .
    ?view vocab:NamedElement_name ?viewName .
  }
}
LIMIT 25

