  ?bb (vocab:Element_ownedElement|vocab:Namespace_member)+ ?child .
  FILTER(?child != ?bb)

  ?req rdf:type vocab:tmt%20requirement .
  ?req vocab:NamedElement_name ?reqName .

  {
    ?child (vocab:Dependency_supplier|^vocab:Dependency_supplier|vocab:Dependency_client|^vocab:Dependency_client)+ ?req .
  }
  UNION
  {
    ?child (vocab:satisfy|vocab:verify|vocab:allocate)+ ?req .
